fun book(seat: Seat, user: User?): Ticket {
    requireNotNull(user) { "user must be logged in" }   // argument
    check(!seat.locked) { "seat map is locked" }          // state
    return when (seat.status) {
        FREE     -> issue(seat, user)
        HELD     -> waitlist(seat, user)
        OCCUPIED -> error("unreachable: filtered upstream")
    }
}

