fun risky(fail: Boolean): Int = try {
    if (fail) throw IllegalStateException()
    1
} catch (e: IllegalStateException) {
    2
} finally {
    println("cleanup")
}

fun main() {
    println(risky(false))
    println(risky(true))
}

