fun classify(x: Any): String = when (x) {
    in 1..9        -> "digit"
    is String      -> "text:${x.length}"
    10, 20, 30     -> "round"
    else           -> "other"
}

fun main() {
    println(classify(7))
    println(classify("hi"))
    println(classify(20))
    println(classify(3.14))
}
